'use client';
import { useEffect, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { api } from '@/lib/api';
import { Alert } from '@/lib/types';
import { 
  BellRing, 
  Search, 
  Filter, 
  RefreshCw, 
  ShieldAlert, 
  CheckCircle2, 
  Clock, 
  ExternalLink,
  Zap,
  ChevronDown
} from 'lucide-react';
import Link from 'next/link';
import { format } from 'date-fns';

export default function AlertsPage() {
  const [alerts, setAlerts] = useState<Alert[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [filter, setFilter] = useState<'all' | 'unread' | 'high'>('all');

  const fetchData = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true);
    try {
      const data = await api.getAllAlerts(50);
      setAlerts(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const markRead = async (id: string) => {
    try {
      await api.markAlertRead(id);
      setAlerts(prev => prev.map(a => a.id === id ? { ...a, is_read: true } : a));
    } catch (e) { console.error(e); }
  };

  const filteredAlerts = alerts.filter(a => {
    if (filter === 'unread') return !a.is_read;
    if (filter === 'high') return a.severity === 'high';
    return true;
  });

  return (
    <div className="p-10 space-y-10 min-h-screen">
      {/* ΓöÇΓöÇ Header ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <h1 className="text-4xl font-black text-rakshak-navy tracking-tight">System Risk Feed</h1>
            <div className="bg-red-50 text-red-600 text-[10px] font-black px-2.5 py-1 rounded-lg uppercase tracking-widest border border-red-100 flex items-center gap-2">
              <Zap className="w-3 h-3 animate-pulse" />
              Live Anomalies
            </div>
          </div>
          <p className="text-slate-500 font-medium">Real-time integrity breaches and evidence deficits across the national asset network.</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-100 p-1 rounded-xl">
             <button 
                onClick={() => setFilter('all')}
                className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'all' ? 'bg-white text-rakshak-blue shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
             >
                All
             </button>
             <button 
                onClick={() => setFilter('unread')}
                className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'unread' ? 'bg-white text-red-600 shadow-sm' : 'text-slate-400 hover:text-red-400'}`}
             >
                Unread
             </button>
             <button 
                onClick={() => setFilter('high')}
                className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'high' ? 'bg-red-600 text-white shadow-lg shadow-red-500/20' : 'text-slate-400 hover:text-red-500'}`}
             >
                High Risk
             </button>
          </div>

          <button 
            onClick={() => fetchData(true)}
            className={`p-4 bg-white border border-slate-200 rounded-2xl shadow-sm hover:bg-slate-50 transition-all ${refreshing ? 'animate-spin' : ''}`}
          >
            <RefreshCw className="w-5 h-5 text-slate-600" />
          </button>
        </div>
      </div>

      <div className="grid md:grid-cols-4 gap-10">
        <div className="md:col-span-3 space-y-6">
           {loading ? (
             <div className="space-y-4 animate-pulse">
                {[1, 2, 3, 4, 5].map(i => <div key={i} className="h-24 bg-slate-200 rounded-2xl" />)}
             </div>
           ) : filteredAlerts.length === 0 ? (
             <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-slate-100 italic">
                <CheckCircle2 className="w-16 h-16 text-green-100 mb-4" />
                <p className="text-slate-400 font-black uppercase tracking-widest text-xs">No critical anomalies registered in this view</p>
             </div>
           ) : (
             <div className="space-y-4">
                <AnimatePresence>
                   {filteredAlerts.map((alert, i) => (
                      <motion.div
                         key={alert.id}
                         initial={{ opacity: 0, x: -20 }}
                         animate={{ opacity: 1, x: 0 }}
                         exit={{ opacity: 0, x: 20 }}
                         transition={{ delay: i * 0.05 }}
                         className={`group glass-card p-6 border-l-4 transition-all hover:bg-white/95 ${
                            alert.is_read ? 'border-slate-100 bg-slate-50 opacity-70' : 
                            alert.severity === 'high' ? 'border-red-500 bg-white' : 'border-yellow-500 bg-white'
                         } flex items-center gap-6`}
                      >
                         <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 ${
                            alert.is_read ? 'bg-slate-200 text-slate-400' : 
                            alert.severity === 'high' ? 'bg-red-50 text-red-500 shadow-lg shadow-red-500/10' : 'bg-yellow-50 text-yellow-500'
                         }`}>
                            {alert.severity === 'high' ? <ShieldAlert className="w-7 h-7" /> : <BellRing className="w-7 h-7" />}
                         </div>

                         <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-3 mb-1">
                               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{alert.alert_type.replace('_', ' ')}</p>
                               <span className="text-[10px] text-slate-300 font-bold">ΓÇó</span>
                               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{format(new Date(alert.created_at!), 'dd MMM HH:mm')}</p>
                            </div>
                            <h3 className="font-black text-rakshak-navy text-lg leading-tight mb-1 group-hover:text-rakshak-blue transition-colors truncate">
                               {alert.title}
                            </h3>
                            <p className="text-sm font-medium text-slate-500 line-clamp-1">{alert.message}</p>
                         </div>

                         <div className="flex items-center gap-4">
                            <Link href={`/dashboard/projects/${alert.project_id}`}>
                               <button className="flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase bg-slate-100 text-slate-600 hover:bg-rakshak-blue hover:text-white transition-all">
                                  Investigate
                                  <ExternalLink className="w-3 h-3" />
                               </button>
                            </Link>
                            {!alert.is_read && (
                               <button 
                                  onClick={() => markRead(alert.id)}
                                  className="p-3 bg-white border border-slate-200 rounded-xl hover:bg-blue-50 text-slate-400 hover:text-rakshak-blue shadow-sm transition-all"
                               >
                                  <CheckCircle2 className="w-4 h-4" />
                               </button>
                            )}
                         </div>
                      </motion.div>
                   ))}
                </AnimatePresence>
             </div>
           )}
        </div>

        <div className="space-y-8">
           <div className="glass-card p-8 bg-gradient-to-br from-rakshak-navy to-slate-900 text-white rounded-3xl shadow-xl overflow-hidden relative">
              <div className="relative z-10">
                 <h4 className="text-[10px] font-black uppercase tracking-[0.3em] text-blue-400 mb-6 border-b border-white/10 pb-4">National Risk Heat</h4>
                 <div className="space-y-6">
                    <div>
                       <div className="flex justify-between items-end mb-2">
                          <span className="text-xs font-bold opacity-60">Critical Assets</span>
                          <span className="text-xl font-black text-red-400">08</span>
                       </div>
                       <div className="h-1.5 bg-white/10 rounded-full overflow-hidden">
                          <div className="bg-red-500 h-full w-[15%]" />
                       </div>
                    </div>
                    <div>
                       <div className="flex justify-between items-end mb-2">
                          <span className="text-xs font-bold opacity-60">Resource Diversion</span>
                          <span className="text-xl font-black text-yellow-400">14%</span>
                       </div>
                       <div className="h-1.5 bg-white/10 rounded-full overflow-hidden">
                          <div className="bg-yellow-500 h-full w-[34%]" />
                       </div>
                    </div>
                 </div>
              </div>
              <div className="absolute top-0 right-0 w-32 h-32 bg-red-500/10 blur-3xl -translate-y-1/2 translate-x-1/2" />
           </div>

           <div className="glass-card p-8 bg-white border border-slate-100 rounded-3xl shadow-card">
              <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6 flex items-center gap-2">
                 <Clock className="w-4 h-4" />
                 Last 24 Hours
              </h4>
              <div className="space-y-6">
                 <div className="flex items-start gap-4">
                    <div className="w-2 h-2 rounded-full bg-red-500 mt-1.5 shrink-0" />
                    <div>
                       <p className="text-xs font-bold text-rakshak-navy">High-speed rail corridor report delayed by 18h.</p>
                       <p className="text-[10px] text-slate-400 font-medium">09:44 AM</p>
                    </div>
                 </div>
                 <div className="flex items-start gap-4">
                    <div className="w-2 h-2 rounded-full bg-yellow-500 mt-1.5 shrink-0" />
                    <div>
                       <p className="text-xs font-bold text-rakshak-navy">Budget deviation (8%) detected in Bangalore Metro Ph-3.</p>
                       <p className="text-[10px] text-slate-400 font-medium">07:12 AM</p>
                    </div>
                 </div>
                 <div className="flex items-start gap-4">
                    <div className="w-2 h-2 rounded-full bg-green-500 mt-1.5 shrink-0" />
                    <div>
                       <p className="text-xs font-bold text-rakshak-navy">GPS signature verified for Mumbai Coastal Ph-II.</p>
                       <p className="text-[10px] text-slate-400 font-medium">Yesterday</p>
                    </div>
                 </div>
              </div>
              <button className="w-full mt-8 py-3 bg-slate-50 text-slate-400 font-black uppercase tracking-widest text-[9px] rounded-xl hover:bg-slate-100 transition-all flex items-center justify-center gap-2">
                 Full Audit Log <ChevronDown className="w-3 h-3" />
              </button>
           </div>
        </div>
      </div>
    </div>
  );
}

'use client';
import { useEffect, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { api } from '@/lib/api';
import { Contractor } from '@/lib/types';
import { 
  Building2, 
  Search, 
  Filter, 
  TrendingUp, 
  ShieldAlert, 
  CheckCircle2, 
  Star, 
  ExternalLink,
  ChevronRight,
  UserCheck
} from 'lucide-react';
import Link from 'next/link';

export default function ContractorsPage() {
  const [contractors, setContractors] = useState<Contractor[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  const fetchData = useCallback(async () => {
    try {
      const data = await api.getContractors();
      setContractors(data);
    } catch (e) { console.error(e); }
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const filtered = contractors.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.registration_no?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="p-10 space-y-10 min-h-screen">
      {/* ΓöÇΓöÇ Header ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
           <div className="flex items-center gap-3 mb-2">
              <h1 className="text-4xl font-black text-rakshak-navy tracking-tight">Vendor Integrity Registry</h1>
              <div className="bg-rakshak-blue/10 text-rakshak-blue text-[10px] font-black px-2.5 py-1 rounded-lg uppercase tracking-widest border border-rakshak-blue/10">
                 Pre-Qualified Partners
              </div>
           </div>
           <p className="text-slate-500 font-medium whitespace-pre-wrap">Historical performance tracking and data-driven risk profiling of execution agencies.</p>
        </div>

        <div className="flex items-center gap-4">
           <div className="relative w-64">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                 type="text" 
                 placeholder="Search Vendor/Reg ID..." 
                 value={search}
                 onChange={(e) => setSearch(e.target.value)}
                 className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-2xl text-xs font-bold focus:outline-none focus:ring-2 focus:ring-rakshak-blue/20 transition-all shadow-sm"
              />
           </div>
           <button className="p-4 bg-white border border-slate-200 rounded-2xl shadow-sm hover:bg-slate-50 transition-all text-slate-400">
              <Filter className="w-5 h-5" />
           </button>
        </div>
      </div>

      {loading ? (
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8 animate-pulse">
           {[1, 2, 3, 4, 5, 6].map(i => <div key={i} className="h-48 bg-slate-100 rounded-3xl" />)}
        </div>
      ) : (
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
           <AnimatePresence>
              {filtered.map((c, i) => (
                 <motion.div
                    key={c.id}
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ delay: i * 0.05 }}
                    className="glass-card p-8 bg-white border border-slate-100 shadow-card hover:shadow-card-hover group transition-all rounded-3xl relative overflow-hidden"
                 >
                    <div className="flex items-center justify-between mb-6">
                       <div className="p-3 bg-slate-50 rounded-2xl text-rakshak-blue group-hover:bg-rakshak-blue group-hover:text-white transition-all">
                          <Building2 className="w-6 h-6" />
                       </div>
                       <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[9px] font-black uppercase ${
                          c.risk_score < 30 ? 'bg-green-50 text-green-700 border-green-100' : 'bg-red-50 text-red-700 border-red-100'
                       }`}>
                          {c.risk_score < 30 ? <CheckCircle2 className="w-3 h-3" /> : <ShieldAlert className="w-3 h-3" />}
                          Integrity Rank: {c.risk_score < 30 ? 'A+' : 'C-'}
                       </div>
                    </div>

                    <h3 className="text-xl font-bold text-rakshak-navy mb-1 group-hover:text-rakshak-blue transition-colors">{c.name}</h3>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 border-b border-slate-50 pb-4">REG-ID: {c.registration_no || 'NA'}</p>

                    <div className="grid grid-cols-2 gap-4 mb-6">
                       <div>
                          <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter mb-1">Active Assets</p>
                          <p className="text-lg font-black text-rakshak-navy leading-none">{c.total_projects}</p>
                       </div>
                       <div>
                          <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter mb-1">Avg Delay Days</p>
                          <p className="text-lg font-black text-rakshak-navy leading-none">{c.avg_delay_days}d</p>
                       </div>
                    </div>

                    <div className="pt-6 border-t border-slate-50 flex items-center justify-between">
                       <div className="flex items-center gap-1">
                          {[1, 2, 3, 4, 5].map((star) => (
                             <Star key={star} className={`w-3 h-3 ${star <= (5 - (c.risk_score / 20)) ? 'text-rakshak-gold fill-rakshak-gold' : 'text-slate-200'}`} />
                          ))}
                       </div>
                       <button className="flex items-center gap-2 text-xs font-black uppercase tracking-widest text-rakshak-blue hover:text-rakshak-navy transition-all group-hover:translate-x-1 duration-300">
                          Profile <ChevronRight className="w-4 h-4" />
                       </button>
                    </div>

                    <div className="absolute top-0 right-0 w-32 h-32 bg-rakshak-blue/5 blur-3xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity -z-10 scale-90 translate-x-1/2 -translate-y-1/2" />
                 </motion.div>
              ))}
           </AnimatePresence>
        </div>
      )}

      {/* Trust Badge Footer */}
      <div className="glass-card p-10 bg-slate-50 border border-slate-100 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-8 opacity-75">
          <div className="flex items-center gap-6">
             <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center shadow-xl border border-slate-200">
                <UserCheck className="w-8 h-8 text-green-600" />
             </div>
             <div>
                <h4 className="font-black text-rakshak-navy text-lg tracking-tight uppercase leading-none mb-2">Automated Prequalification Active</h4>
                <p className="text-xs font-medium text-slate-500 max-w-sm">Every vendor listed is verified through the Central Registry of Integrity (CRI) and synced with historical project performance data.</p>
             </div>
          </div>
          <button className="px-8 py-4 bg-white border border-slate-200 text-[10px] font-black uppercase tracking-widest rounded-2xl shadow-xl hover:bg-rakshak-navy hover:text-white transition-all">Submit Verification Query</button>
      </div>
    </div>
  );
}

'use client';
import { useEffect, useState } from 'react';
import DashboardMap from '@/components/DashboardMap';
import { api } from '@/lib/api';
import { ProjectMapPoint } from '@/lib/types';
import { ArrowLeft, Layers, Filter, ShieldCheck, Maximize2 } from 'lucide-react';
import Link from 'next/link';

export default function FullMapPage() {
  const [projects, setProjects] = useState<ProjectMapPoint[]>([]);

  useEffect(() => {
    const fetchMapData = async () => {
      try {
        const data = await api.getMapProjects();
        setProjects(data);
      } catch (e) {
        console.error(e);
      }
    };
    fetchMapData();
  }, []);

  return (
    <div className="h-screen w-full relative bg-slate-100">
      {/* Overlay Header */}
      <div className="absolute top-6 left-6 right-6 z-20 flex justify-between items-start pointer-events-none">
        <div className="flex items-center gap-4 pointer-events-auto">
          <Link href="/dashboard">
            <button className="p-4 bg-white/90 backdrop-blur-xl border border-white shadow-2xl rounded-2xl text-rakshak-navy hover:bg-rakshak-navy hover:text-white transition-all">
              <ArrowLeft className="w-5 h-5" />
            </button>
          </Link>
          <div className="p-4 bg-white/90 backdrop-blur-xl border border-white shadow-2xl rounded-2xl">
            <div className="flex items-center gap-3">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
              <h1 className="text-sm font-black text-rakshak-navy uppercase tracking-widest leading-none">Live National Integrity Map</h1>
            </div>
            <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-tighter">Monitoring {projects.length} Field Operations</p>
          </div>
        </div>

        <div className="pointer-events-auto flex flex-col gap-3">
          <div className="p-4 bg-white/90 backdrop-blur-xl border border-white shadow-2xl rounded-2xl w-64">
             <div className="flex items-center justify-between mb-4 border-b border-slate-100 pb-3">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Map Layers</span>
                <Layers className="w-4 h-4 text-slate-300" />
             </div>
             <div className="space-y-3">
                <div className="flex items-center justify-between">
                    <span className="text-[11px] font-bold text-slate-600">3D Terrain</span>
                    <input type="checkbox" checked readOnly className="accent-rakshak-blue" />
                </div>
                <div className="flex items-center justify-between">
                    <span className="text-[11px] font-bold text-slate-600">Active High Risk</span>
                    <input type="checkbox" checked readOnly className="accent-red-500" />
                </div>
                <div className="flex items-center justify-between">
                    <span className="text-[11px] font-bold text-slate-600">Verified Evidence</span>
                    <input type="checkbox" checked readOnly className="accent-green-500" />
                </div>
             </div>
          </div>

          <div className="p-4 bg-rakshak-navy text-white shadow-2xl rounded-2xl flex items-center justify-between">
             <div className="flex items-center gap-3">
                <ShieldCheck className="w-5 h-5 text-rakshak-saffron" />
                <span className="text-[10px] font-black uppercase tracking-widest">Asset Integrity Secure</span>
             </div>
             <Maximize2 className="w-4 h-4 opacity-50" />
          </div>
        </div>
      </div>

      <div className="h-full w-full">
        <DashboardMap projects={projects} />
      </div>
    </div>
  );
}

'use client';
import { useEffect, useState, useCallback } from 'react';
import { motion } from 'framer-motion';
import { api } from '@/lib/api';
import { DashboardStats, ProjectMapPoint, Alert, WSEvent } from '@/lib/types';
import DashboardStatsGrid from '@/components/DashboardStats';
import DashboardMap from '@/components/DashboardMap';
import AlertFeed from '@/components/AlertFeed';
import { useWebSocket } from '@/lib/use-websocket';
import { 
  Building2, 
  IndianRupee, 
  Map as MapIcon, 
  RefreshCw, 
  Search,
  BellRing,
  ShieldCheck,
  ExternalLink
} from 'lucide-react';
import Link from 'next/link';
import Glass3D from '@/components/Glass3D';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';

import { useRef } from 'react';
import * as THREE from 'three';

function RiskOrb({ score }: { score: number }) {
  const mountRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (!mountRef.current) return;
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, 1, 0.1, 1000);
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(120, 120);
    mountRef.current.appendChild(renderer.domElement);

    const geometry = new THREE.IcosahedronGeometry(1, 15);
    const material = new THREE.MeshPhongMaterial({
      color: score > 50 ? 0xef4444 : 0x3b82f6,
      wireframe: true,
      transparent: true,
      opacity: 0.6,
    });
    const orb = new THREE.Mesh(geometry, material);
    scene.add(orb);

    const light = new THREE.PointLight(0xffffff, 2);
    light.position.set(5, 5, 5);
    scene.add(light);
    scene.add(new THREE.AmbientLight(0xffffff, 0.5));

    camera.position.z = 2.5;

    const animate = () => {
      requestAnimationFrame(animate);
      orb.rotation.y += 0.01;
      orb.rotation.x += 0.005;
      const s = 1 + Math.sin(Date.now() * 0.002) * 0.1;
      orb.scale.set(s, s, s);
      renderer.render(scene, camera);
    };
    animate();

    return () => {
      renderer.dispose();
      mountRef.current?.removeChild(renderer.domElement);
    };
  }, [score]);

  return <div ref={mountRef} className="w-[120px] h-[120px] drop-shadow-[0_0_20px_rgba(59,130,246,0.3)]" />;
}

